#!/bin/bash
# MongoDB Index Optimization Report
set -euo pipefail

DB="mydb"

echo "=== Collection stats ==="
mongosh --quiet --eval "
const collections = db.getCollectionNames();
collections.forEach(c => {
  const stats = db[c].stats();
  print(c + ': ' + stats.count + ' docs, ' +
    Math.round(stats.size / 1024 / 1024) + 'MB data, ' +
    Math.round(stats.totalIndexSize / 1024 / 1024) + 'MB indexes, ' +
    stats.nindexes + ' indexes');
});
" "$DB"

echo ""
echo "=== Index usage stats (all collections) ==="
mongosh --quiet --eval "
const collections = db.getCollectionNames();
collections.forEach(c => {
  print('--- ' + c + ' ---');
  const stats = db[c].aggregate([{$indexStats: {}}]).toArray();
  stats.forEach(s => {
    print('  ' + s.name + ': ' + s.accesses.ops + ' ops since ' + s.accesses.since);
  });
});
" "$DB"

echo ""
echo "=== Potentially unused indexes (0 ops) ==="
mongosh --quiet --eval "
const collections = db.getCollectionNames();
collections.forEach(c => {
  const stats = db[c].aggregate([{$indexStats: {}}]).toArray();
  stats.filter(s => s.accesses.ops === 0 && s.name !== '_id_').forEach(s => {
    print(c + '.' + s.name + ' (0 ops since ' + s.accesses.since + ')');
  });
});
" "$DB"

echo ""
echo "=== Index sizes ==="
mongosh --quiet --eval "
const collections = db.getCollectionNames();
collections.forEach(c => {
  const sizes = db[c].stats().indexSizes;
  Object.keys(sizes).forEach(idx => {
    print(c + '.' + idx + ': ' + Math.round(sizes[idx] / 1024) + 'KB');
  });
});
" "$DB"
